import{_ as r,c as t,o as a,a2 as o}from"./chunks/framework.CIiVzG-O.js";const u=JSON.parse('{"title":"Usage Guide","description":"","frontmatter":{},"headers":[],"relativePath":"guide/usage.md","filePath":"guide/usage.md","lastUpdated":1783607180000}'),i={name:"guide/usage.md"};function l(s,e,n,c,h,d){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="usage-guide" tabindex="-1">Usage Guide <a class="header-anchor" href="#usage-guide" aria-label="Permalink to &quot;Usage Guide&quot;">​</a></h1><h2 id="opening-archives" tabindex="-1">Opening Archives <a class="header-anchor" href="#opening-archives" aria-label="Permalink to &quot;Opening Archives&quot;">​</a></h2><h3 id="double-click-to-open" tabindex="-1">Double-Click to Open <a class="header-anchor" href="#double-click-to-open" aria-label="Permalink to &quot;Double-Click to Open&quot;">​</a></h3><p>NueZip registers itself as the default handler for all supported archive formats. Simply double-click any archive file (<code>.zip</code>, <code>.rar</code>, <code>.7z</code>, <code>.tar</code>, <code>.gz</code>, <code>.bz2</code>, <code>.xz</code>, <code>.zst</code>) to open it in NueZip&#39;s main window.</p><h3 id="open-with-nuezip-finder-context-menu" tabindex="-1">Open with NueZip (Finder Context Menu) <a class="header-anchor" href="#open-with-nuezip-finder-context-menu" aria-label="Permalink to &quot;Open with NueZip (Finder Context Menu)&quot;">​</a></h3><p>Right-click any archive file and select <strong>Open with NueZip</strong> from the context menu. The Finder extension also provides quick actions:</p><ul><li><strong>Extract Here</strong> — Extract archive contents to the current folder</li><li><strong>Extract to &quot;FolderName/&quot;</strong> — Extract to a named subfolder</li><li><strong>Compress to ZIP</strong> — Compress selected files/folders to a ZIP archive</li><li><strong>Open with NueZip</strong> — Open in the main browser window</li></ul><h3 id="drag-drop-to-tray" tabindex="-1">Drag &amp; Drop to Tray <a class="header-anchor" href="#drag-drop-to-tray" aria-label="Permalink to &quot;Drag &amp; Drop to Tray&quot;">​</a></h3><p>Drag any archive file onto the NueZip menu bar icon to quickly open it in the drop panel for instant access. You can also drag files onto the tray icon to compress them.</p><h2 id="extracting-archives" tabindex="-1">Extracting Archives <a class="header-anchor" href="#extracting-archives" aria-label="Permalink to &quot;Extracting Archives&quot;">​</a></h2><h3 id="basic-extraction" tabindex="-1">Basic Extraction <a class="header-anchor" href="#basic-extraction" aria-label="Permalink to &quot;Basic Extraction&quot;">​</a></h3><ol><li>Open an archive in NueZip</li><li>Click the <strong>Extract</strong> button in the toolbar</li><li>Choose a destination folder</li><li>Click <strong>Extract</strong></li></ol><h3 id="quick-extract-from-finder" tabindex="-1">Quick Extract from Finder <a class="header-anchor" href="#quick-extract-from-finder" aria-label="Permalink to &quot;Quick Extract from Finder&quot;">​</a></h3><p>Right-click an archive in Finder and select one of the quick actions:</p><ul><li><strong>Extract Here</strong> — Extracts directly to the current folder</li><li><strong>Extract to &quot;[ArchiveName]/&quot;</strong> — Extracts to a named subfolder for clean organization</li></ul><h3 id="extract-with-password" tabindex="-1">Extract with Password <a class="header-anchor" href="#extract-with-password" aria-label="Permalink to &quot;Extract with Password&quot;">​</a></h3><p>For password-protected archives, NueZip will prompt for the password. The built-in password manager can store credentials securely in your local keychain for future use.</p><h2 id="compressing-archives" tabindex="-1">Compressing Archives <a class="header-anchor" href="#compressing-archives" aria-label="Permalink to &quot;Compressing Archives&quot;">​</a></h2><h3 id="create-a-new-archive" tabindex="-1">Create a New Archive <a class="header-anchor" href="#create-a-new-archive" aria-label="Permalink to &quot;Create a New Archive&quot;">​</a></h3><ol><li>Select files or folders in NueZip&#39;s main window</li><li>Click the <strong>Compress</strong> button in the toolbar</li><li>Choose the archive format (ZIP, 7z, TAR, GZIP, etc.)</li><li>Configure compression settings (level, encryption method)</li><li>Click <strong>Compress</strong></li></ol><h3 id="compress-from-finder" tabindex="-1">Compress from Finder <a class="header-anchor" href="#compress-from-finder" aria-label="Permalink to &quot;Compress from Finder&quot;">​</a></h3><p>Right-click files/folders in Finder and select <strong>Compress with NueZip</strong>:</p><ul><li><strong>Compress to ZIP</strong> — Quick ZIP archive creation</li><li><strong>Compress with Options</strong> — Opens NueZip with advanced settings</li></ul><h3 id="compress-via-drag-drop" tabindex="-1">Compress via Drag &amp; Drop <a class="header-anchor" href="#compress-via-drag-drop" aria-label="Permalink to &quot;Compress via Drag &amp; Drop&quot;">​</a></h3><p>Drag files onto the NueZip menu bar tray icon to quickly create a ZIP archive.</p><h2 id="batch-operations" tabindex="-1">Batch Operations <a class="header-anchor" href="#batch-operations" aria-label="Permalink to &quot;Batch Operations&quot;">​</a></h2><h3 id="batch-compress" tabindex="-1">Batch Compress <a class="header-anchor" href="#batch-compress" aria-label="Permalink to &quot;Batch Compress&quot;">​</a></h3><ol><li>Select multiple items in NueZip</li><li>Choose <strong>Batch Compress</strong> from the toolbar or File menu</li><li>Each item will be compressed into a separate archive</li></ol><h3 id="batch-extract" tabindex="-1">Batch Extract <a class="header-anchor" href="#batch-extract" aria-label="Permalink to &quot;Batch Extract&quot;">​</a></h3><ol><li>Select multiple archives in NueZip</li><li>Choose <strong>Batch Extract</strong> from the toolbar or File menu</li><li>All archives will be extracted simultaneously</li></ol><h3 id="batch-convert" tabindex="-1">Batch Convert <a class="header-anchor" href="#batch-convert" aria-label="Permalink to &quot;Batch Convert&quot;">​</a></h3><ol><li>Select one or more archives</li><li>Choose <strong>Convert</strong> → select target format</li><li>NueZip will recompress each archive into the chosen format</li></ol><h3 id="batch-encrypt" tabindex="-1">Batch Encrypt <a class="header-anchor" href="#batch-encrypt" aria-label="Permalink to &quot;Batch Encrypt&quot;">​</a></h3><ol><li>Select multiple ZIP archives</li><li>Choose <strong>Batch Encrypt</strong></li><li>Set a password — all selected archives will be password-protected</li></ol><h2 id="format-conversion" tabindex="-1">Format Conversion <a class="header-anchor" href="#format-conversion" aria-label="Permalink to &quot;Format Conversion&quot;">​</a></h2><p>Convert archives between any supported formats:</p><ol><li>Open an archive</li><li>Click <strong>Convert</strong> in the toolbar</li><li>Select the target format (e.g., RAR → ZIP, 7z → TAR.GZ)</li><li>Choose output location</li><li>Click <strong>Convert</strong></li></ol><h2 id="archive-repair" tabindex="-1">Archive Repair <a class="header-anchor" href="#archive-repair" aria-label="Permalink to &quot;Archive Repair&quot;">​</a></h2><p>For corrupted RAR or ZIP archives:</p><ol><li>Open the corrupted archive</li><li>Click <strong>Repair</strong> in the toolbar</li><li>NueZip will attempt to reconstruct the archive data</li><li>The repaired archive is saved as a new file</li></ol><h2 id="archive-search" tabindex="-1">Archive Search <a class="header-anchor" href="#archive-search" aria-label="Permalink to &quot;Archive Search&quot;">​</a></h2><p>Find specific files within archives:</p><ol><li>Click the <strong>Search</strong> button in the toolbar</li><li>Enter a filename pattern</li><li>NueZip searches through all entries in the open archive</li><li>Results are displayed with full paths for quick navigation</li></ol><h2 id="performance-benchmark" tabindex="-1">Performance Benchmark <a class="header-anchor" href="#performance-benchmark" aria-label="Permalink to &quot;Performance Benchmark&quot;">​</a></h2><p>Test your system&#39;s compression performance:</p><ol><li>Go to <strong>Tools → Benchmark</strong></li><li>NueZip runs compression tests using various formats and settings</li><li>Results show compression speed (MB/s) and ratio for each format</li><li>Use this to compare performance across different compression methods</li></ol><h2 id="multi-volume-split-archives" tabindex="-1">Multi-Volume (Split) Archives <a class="header-anchor" href="#multi-volume-split-archives" aria-label="Permalink to &quot;Multi-Volume (Split) Archives&quot;">​</a></h2><p>Create split archives for large data:</p><ol><li>During compression, enable <strong>Split into volumes</strong></li><li>Choose volume size (e.g., 100 MB, 650 MB, 4.7 GB, or custom)</li><li>NueZip creates numbered part files (<code>.zip.001</code>, <code>.zip.002</code>, etc.)</li><li>To extract, open the first part file — NueZip automatically loads the rest</li></ol><ul><li><strong>Password</strong>: Provide a password for encrypted archives</li><li><strong>Wrap in Folder</strong>: Automatically create a root folder if the archive has no single root directory</li><li><strong>Open After</strong>: Reveal the extracted files in Finder upon completion</li><li><strong>Keep Broken Files</strong>: Preserve any files extracted before an error (for partial recovery)</li><li><strong>Update Mode</strong>: Choose how to handle existing files (overwrite, skip, rename)</li></ul><h3 id="batch-extraction" tabindex="-1">Batch Extraction <a class="header-anchor" href="#batch-extraction" aria-label="Permalink to &quot;Batch Extraction&quot;">​</a></h3><ol><li>Go to <strong>Tools → Batch Extract</strong></li><li>Click <strong>Add Files...</strong> to select archive files</li><li>Choose a destination folder</li><li>Optionally enable <strong>Delete source files after extraction</strong></li><li>Click <strong>Start</strong></li></ol><h2 id="creating-archives" tabindex="-1">Creating Archives <a class="header-anchor" href="#creating-archives" aria-label="Permalink to &quot;Creating Archives&quot;">​</a></h2><h3 id="compress-files" tabindex="-1">Compress Files <a class="header-anchor" href="#compress-files" aria-label="Permalink to &quot;Compress Files&quot;">​</a></h3><ol><li>Click the <strong>Compress</strong> button in the toolbar</li><li>Select files to compress (or drag and drop them into the window)</li><li>Choose <strong>Archive Format</strong>: ZIP, 7Z, TAR, GZIP, BZIP2</li><li>Configure <strong>Compression Method</strong> and level</li><li>Set <strong>Save Location</strong> and archive name</li><li>Optionally set a <strong>Password</strong> for encryption</li><li>Optionally set <strong>Split Size</strong> for multi-volume archives</li><li>Click <strong>Compress</strong></li></ol><h3 id="add-files-to-existing-archive" tabindex="-1">Add Files to Existing Archive <a class="header-anchor" href="#add-files-to-existing-archive" aria-label="Permalink to &quot;Add Files to Existing Archive&quot;">​</a></h3><ol><li>Open an existing archive in NueZip</li><li>Click <strong>Add Files</strong> in the toolbar</li><li>Select files to add</li><li>Click <strong>Add</strong></li></ol><h2 id="batch-operations-1" tabindex="-1">Batch Operations <a class="header-anchor" href="#batch-operations-1" aria-label="Permalink to &quot;Batch Operations&quot;">​</a></h2><h3 id="batch-compress-1" tabindex="-1">Batch Compress <a class="header-anchor" href="#batch-compress-1" aria-label="Permalink to &quot;Batch Compress&quot;">​</a></h3><ol><li>Go to <strong>Tools → Batch Compress</strong></li><li>Click <strong>Select Files/Folders...</strong> to choose items</li><li>Each selected item will become a separate archive</li><li>Configure output <strong>Format</strong>, <strong>Save Location</strong>, and file naming prefix</li><li>Click <strong>Start</strong></li></ol><h3 id="batch-convert-format" tabindex="-1">Batch Convert Format <a class="header-anchor" href="#batch-convert-format" aria-label="Permalink to &quot;Batch Convert Format&quot;">​</a></h3><ol><li>Go to <strong>Tools → Batch Convert Format</strong></li><li>Click <strong>Add Files...</strong> to select source archives</li><li>Choose <strong>Target Format</strong></li><li>Optionally enable <strong>Delete source files after conversion</strong></li><li>Click <strong>Start</strong></li></ol><h3 id="batch-encrypt-1" tabindex="-1">Batch Encrypt <a class="header-anchor" href="#batch-encrypt-1" aria-label="Permalink to &quot;Batch Encrypt&quot;">​</a></h3><ol><li>Go to <strong>Tools → Batch Encrypt</strong></li><li>Click <strong>Add Files...</strong> to select archives</li><li>Enter a <strong>Password</strong></li><li>Click <strong>Encrypt</strong></li></ol><h2 id="advanced-features" tabindex="-1">Advanced Features <a class="header-anchor" href="#advanced-features" aria-label="Permalink to &quot;Advanced Features&quot;">​</a></h2><h3 id="archive-repair-1" tabindex="-1">Archive Repair <a class="header-anchor" href="#archive-repair-1" aria-label="Permalink to &quot;Archive Repair&quot;">​</a></h3><p>Repair corrupted or damaged archives:</p><ol><li>Select the damaged archive</li><li>Go to <strong>Tools → Repair Archive</strong></li><li>NueZip will scan the header, rebuild the directory, and fix data blocks</li><li>Review the repair result</li></ol><h3 id="format-conversion-1" tabindex="-1">Format Conversion <a class="header-anchor" href="#format-conversion-1" aria-label="Permalink to &quot;Format Conversion&quot;">​</a></h3><p>Convert archives between formats:</p><ol><li>Open an archive or select a file</li><li>Go to <strong>File → Convert Format</strong></li><li>Choose the target format and compression level</li><li>Optionally delete the original file</li><li>Click <strong>Convert</strong></li></ol><h3 id="password-manager" tabindex="-1">Password Manager <a class="header-anchor" href="#password-manager" aria-label="Permalink to &quot;Password Manager&quot;">​</a></h3><p>NueZip securely stores archive passwords in your local keychain:</p><ol><li>Go to <strong>Tools → Password Manager</strong></li><li>View all saved passwords</li><li>Add, edit, or delete entries</li><li>Passwords are automatically applied when opening matching encrypted archives</li></ol><h3 id="performance-benchmark-1" tabindex="-1">Performance Benchmark <a class="header-anchor" href="#performance-benchmark-1" aria-label="Permalink to &quot;Performance Benchmark&quot;">​</a></h3><p>Test your system&#39;s compression performance:</p><ol><li>Go to <strong>Tools → Performance Benchmark</strong></li><li>Select a test file (or use the default)</li><li>Click <strong>Test</strong></li><li>View results including compress/decompress speed and rating</li></ol><h3 id="archive-search-1" tabindex="-1">Archive Search <a class="header-anchor" href="#archive-search-1" aria-label="Permalink to &quot;Archive Search&quot;">​</a></h3><p>Find files within archives:</p><ol><li>Open an archive</li><li>Press <code>Cmd+F</code> or click the search icon</li><li>Enter a filename, optionally matching case or whole word</li><li>Browse search results and click to navigate</li></ol><h2 id="keyboard-shortcuts" tabindex="-1">Keyboard Shortcuts <a class="header-anchor" href="#keyboard-shortcuts" aria-label="Permalink to &quot;Keyboard Shortcuts&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Shortcut</th><th>Action</th></tr></thead><tbody><tr><td><code>Cmd+O</code></td><td>Open archive</td></tr><tr><td><code>Cmd+N</code></td><td>New archive</td></tr><tr><td><code>Cmd+E</code></td><td>Extract</td></tr><tr><td><code>Cmd+F</code></td><td>Find in archive</td></tr><tr><td><code>Cmd+,</code></td><td>Open settings</td></tr><tr><td><code>Cmd+W</code></td><td>Close window</td></tr><tr><td><code>Cmd+Q</code></td><td>Quit application</td></tr><tr><td><code>Cmd+↑</code></td><td>Go up one level</td></tr><tr><td><code>Cmd+→</code></td><td>Go forward</td></tr></tbody></table><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to &quot;Settings&quot;">​</a></h2><p>Access settings through <strong>NueZip → Settings</strong> or press <code>Cmd+,</code>:</p><ul><li><strong>General</strong>: Language, launch at login, appearance theme</li><li><strong>Compression</strong>: Default format, compression level, split size</li><li><strong>Extraction</strong>: Default destination, wrap behavior, conflict resolution</li><li><strong>Folder Access</strong>: Manage folder permissions and bookmarks</li><li><strong>Advanced</strong>: Hardware acceleration, thread count, temporary directory</li><li><strong>Privacy</strong>: Data collection preferences</li></ul>',85)])])}const m=r(i,[["render",l]]);export{u as __pageData,m as default};
